module top_module(
  input clk,
  input reset,
  input [3:0] A,
  input [3:0] B,
  output [3:0] S
);reg [3:0] overflow_flag;
reg [3:0] sum;

always @ (posedge clk or negedge reset) begin
  if (!reset) begin
    overflow_flag <= 4'b0;
    sum <= 4'b0;
  end else begin
    overflow_flag <= {overflow_flag[2:0], A[3]&B[3] | A[3]&overflow_flag[3] | B[3]&overflow_flag[3]};
    sum <= A + B + overflow_flag;
  end
end

assign S = sum;

endmodule
